#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
    for (int j = 0; j < N; ++j) {
        for (int i = 0; i < N; ++i) {
            if (i == 0 || i == N-1) {
                f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
            }
            else if (j == 0 || j == N-1) {
                f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
            }
            else {
                f[IDX(i,j)] = 0.0f;
            }
        }
    }
}

__global__ void compute_step(float* f, float* f_old, float* error_ptr, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_threads = blockDim.x * gridDim.x;

    float local_error = 0.0f;

    for (int work = idx; work < (N-2) * (N-2); work += total_threads) {
        int i = 1 + (work % (N-2));
        int j = 1 + (work / (N-2));

        float t = 0.25f * (f_old[IDX(i-1,j)] +
                           f_old[IDX(i+1,j)] +
                           f_old[IDX(i,j-1)] +
                           f_old[IDX(i,j+1)]);
        float df = t - f_old[IDX(i, j)];
        f[IDX(i,j)] = t;
        local_error += df * df;
    }

    atomicAdd(error_ptr, local_error);
}

__global__ void copy_f_to_f_old(float* f, float* f_old, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_threads = blockDim.x * gridDim.x;

    for (int work = idx; work < N * N; work += total_threads) {
        int i = work % N;
        int j = work / N;

        if (j >= 1 && j <= N-2 && i >= 1 && i <= N-2) {
            f_old[IDX(i,j)] = f[IDX(i,j)];
        }
    }
}

int main() {
    auto start_time = std::chrono::steady_clock::now();

    float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
    float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    initialize_data(f);
    initialize_data(f_old);

    float* d_f, *d_f_old, *d_error;
    cudaMalloc(&d_f, N * N * sizeof(float));
    cudaMalloc(&d_f_old, N * N * sizeof(float));
    cudaMalloc(&d_error, sizeof(float));

    cudaMemcpy(d_f, f, N * N * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_f_old, f_old, N * N * sizeof(float), cudaMemcpyHostToDevice);

    const int max_iters = 10000;
    int num_iters = 0;

    auto start = std::chrono::steady_clock::now();

    int num_threads = 256;
    int num_blocks = (N * N) / num_threads;

    while (error > tolerance && num_iters < max_iters) {
        float zero = 0.0f;
        cudaMemcpy(d_error, &zero, sizeof(float), cudaMemcpyHostToDevice);

        compute_step<<<num_blocks, num_threads>>>(d_f, d_f_old, d_error, N);
        cudaDeviceSynchronize();

        copy_f_to_f_old<<<num_blocks, num_threads>>>(d_f, d_f_old, N);
        cudaDeviceSynchronize();

        cudaMemcpy(&error, d_error, sizeof(float), cudaMemcpyDeviceToHost);

        error = sqrtf(error / (N * N));

        if (num_iters % 1000 == 0) {
            std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
        }

        ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    cudaMemcpy(f, d_f, N * N * sizeof(float), cudaMemcpyDeviceToHost);

    if (error <= tolerance && num_iters < max_iters) {
        std::cout << "PASS" << std::endl;
    }
    else {
        std::cout << "FAIL" << std::endl;
        cudaFree(d_f);
        cudaFree(d_f_old);
        cudaFree(d_error);
        free(f);
        free(f_old);
        return -1;
    }

    cudaFree(d_f);
    cudaFree(d_f_old);
    cudaFree(d_error);

    free(f);
    free(f_old);

    auto end_time = std::chrono::steady_clock::now();
    auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
    double duration = total_time * 1e-9;
    std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

    return 0;
}
